request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?body ?text ?value WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("the APS")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("APS Notes"))
  )
  ?elem rdf:type ?type .

  OPTIONAL {
    ?elem vocab:comment ?body .
  }
  OPTIONAL {
    ?comment vocab:annotatedElement ?elem .
    ?comment vocab:body ?body .
  }
  OPTIONAL {
    ?elem vocab:body ?text .
  }
  OPTIONAL {
    ?elem vocab:body ?value .
  }
  OPTIONAL {
    ?elem vocab:Element_ownedElement ?child .
    ?child vocab:NamedElement_name ?cname .
    FILTER(CONTAINS(LCASE(STR(?cname)), LCASE("APS")))
    OPTIONAL { ?child vocab:body ?text . }
    OPTIONAL { ?child vocab:body ?value . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?prop ?obj WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS%20Notes")))
  OPTIONAL { ?elem rdf:type ?type . }
  ?elem ?prop ?obj .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?lit ?val ?ownerName WHERE {
  ?lit rdf:type ?litType .
  FILTER(?litType IN (vocab:literal%20string, vocab:literal%20integer))
  OPTIONAL { ?lit vocab:NamedElement_name ?valName . }
  OPTIONAL { ?lit vocab:value ?val . }
  FILTER(
    (bound(?val) && (CONTAINS(LCASE(STR(?val)), "aps"))) ||
    (bound(?valName) && CONTAINS(LCASE(STR(?valName)), "aps"))
  )
  OPTIONAL {
    ?lit vocab:Element_owner ?owner .
    OPTIONAL { ?owner vocab:NamedElement_name ?ownerName . }
  }
  FILTER(!CONTAINS(LCASE(STR(?val)), "http"))
}
LIMIT 25
